+    /// Oracle: TRIGGER behavior — BEFORE/AFTER INSERT/UPDATE/DELETE.
+    #[test]
+    fn test_conformance_trigger_behavior_complex() {
+        let fconn = Connection::open(":memory:").unwrap();
+        let rconn = rusqlite::Connection::open_in_memory().unwrap();
