+            "UPDATE t SET val = 'HELLO' WHERE id = 1",
+            "DELETE FROM t WHERE id = 2",
+        ] {
+            fconn.execute(s).unwrap();
+            rconn.execute_batch(s).unwrap();
+        }
+
+        let queries = [
+            "SELECT * FROM t ORDER BY id",
+            "SELECT action, old_val, new_val FROM audit ORDER BY rowid",
